import { useMemo } from 'react';
import {
  Box,
  Typography,
  Tooltip,
  Card,
  makeStyles,
  useTheme,
} from '@material-ui/core';
import ExtensionIcon from '@material-ui/icons/Extension';
import CheckCircleOutlineIcon from '@material-ui/icons/CheckCircleOutline';
import HelpOutlineIcon from '@material-ui/icons/HelpOutline';
import OpenInNewIcon from '@material-ui/icons/OpenInNew';
import {
  type CollectionDependency,
  type ProjectQualityData,
  SEVERITY_COLORS,
} from './qualityDemoData';

const useStyles = makeStyles(theme => ({
  root: {
    padding: '24px 0',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
    gap: 16,
    marginTop: 16,
  },
  card: {
    borderRadius: 8,
    padding: 16,
    display: 'flex',
    flexDirection: 'column' as const,
    gap: 12,
    cursor: 'default',
    transition: 'border-color 0.15s',
    '&:hover': {
      borderColor: theme.palette.primary.main,
    },
  },
  fqcn: {
    fontFamily: 'monospace',
    fontSize: 14,
    fontWeight: 600,
    color: theme.palette.text.primary,
  },
  meta: {
    display: 'flex',
    alignItems: 'center',
    gap: 8,
    flexWrap: 'wrap' as const,
  },
  sourceBadge: {
    fontSize: 10,
    fontWeight: 600,
    textTransform: 'uppercase' as const,
    padding: '1px 6px',
    borderRadius: 3,
    letterSpacing: 0.3,
  },
  noData: {
    display: 'flex',
    flexDirection: 'column' as const,
    alignItems: 'center',
    justifyContent: 'center',
    padding: 48,
    color: theme.palette.text.secondary,
    fontSize: 14,
    gap: 8,
  },
  galaxyLink: {
    display: 'inline-flex',
    alignItems: 'center',
    gap: 4,
    fontSize: 12,
    color: theme.palette.primary.main,
    textDecoration: 'none',
    '&:hover': {
      textDecoration: 'underline',
    },
  },
}));

const SOURCE_COLORS: Record<string, { bg: string; color: string }> = {
  specified: { bg: '#e7f1fa', color: '#0066cc' },
  dependency: { bg: '#f4f0e6', color: '#795600' },
  learned: { bg: '#e9f5e9', color: '#3e8635' },
};

const SOURCE_TOOLTIPS: Record<string, string> = {
  specified: 'Listed in the repository requirements file (requirements.yml or galaxy.yml)',
  dependency: 'Pulled in as a dependency of another collection',
  learned: 'Detected from usage in playbook/role code, not explicitly listed in requirements',
};

function galaxyUrl(fqcn: string): string {
  const [namespace, name] = fqcn.split('.');
  return `https://galaxy.ansible.com/ui/repo/published/${namespace}/${name}/`;
}

interface RepositoryCollectionsTabProps {
  quality: ProjectQualityData | null;
  projectName: string;
  onNavigateToDependencies?: () => void;
}

export function RepositoryCollectionsTab({
  quality,
  projectName: _projectName,
  onNavigateToDependencies,
}: RepositoryCollectionsTabProps) {
  const classes = useStyles();
  const theme = useTheme();

  const collections = useMemo(
    () => [...(quality?.collections ?? [])].sort((a, b) => {
      const sourceOrder: Record<string, number> = { specified: 0, learned: 1, dependency: 2 };
      return (sourceOrder[a.source] ?? 9) - (sourceOrder[b.source] ?? 9);
    }),
    [quality],
  );

  if (!quality || collections.length === 0) {
    return (
      <Box className={classes.noData}>
        <ExtensionIcon style={{ fontSize: 40, opacity: 0.3 }} />
        <Typography style={{ fontSize: 16, fontWeight: 500 }}>
          No collections detected
        </Typography>
        <Typography style={{ fontSize: 13, color: theme.palette.text.secondary }}>
          Run a quality scan to detect collections used in this repository.
        </Typography>
      </Box>
    );
  }

  const withViolations = collections.filter(c => c.violations > 0);
  const specified = collections.filter(c => c.source === 'specified');

  return (
    <Box className={classes.root}>
      <Box display="flex" alignItems="center" style={{ gap: 10, marginBottom: 4 }}>
        <Typography style={{ fontSize: 13 }}>
          <strong>{collections.length}</strong> collection{collections.length !== 1 ? 's' : ''} detected
          {specified.length > 0 && specified.length < collections.length && (
            <span style={{ color: theme.palette.text.secondary }}>
              {' '}· {specified.length} specified, {collections.length - specified.length} from dependencies
            </span>
          )}
        </Typography>
        {withViolations.length > 0 && (
          <>
            <span style={{ color: theme.palette.divider }}>|</span>
            <span
              onClick={onNavigateToDependencies}
              style={{
                fontSize: 11,
                fontWeight: 600,
                padding: '1px 7px',
                borderRadius: 10,
                backgroundColor: `${SEVERITY_COLORS.high}15`,
                color: SEVERITY_COLORS.high,
                cursor: onNavigateToDependencies ? 'pointer' : 'default',
              }}
            >
              {withViolations.length} with violations
            </span>
          </>
        )}
      </Box>

      <Box display="flex" alignItems="center" style={{ gap: 6, marginBottom: 8 }}>
        <Typography style={{ fontSize: 12, color: theme.palette.text.secondary }}>
          Discovered from latest quality scan · {quality.lastScannedAt}
        </Typography>
        <Tooltip
          title="Collections are detected by analyzing this repository's requirements files and code usage during quality scans."
          arrow
          placement="bottom-start"
        >
          <HelpOutlineIcon style={{ fontSize: 14, color: theme.palette.text.secondary, opacity: 0.5, cursor: 'help' }} />
        </Tooltip>
      </Box>

      <Box className={classes.grid}>
        {collections.map(c => (
          <CollectionCard
            key={c.fqcn}
            collection={c}
            onNavigateToDependencies={onNavigateToDependencies}
          />
        ))}
      </Box>
    </Box>
  );
}

function CollectionCard({
  collection: c,
  onNavigateToDependencies,
}: {
  collection: CollectionDependency;
  onNavigateToDependencies?: () => void;
}) {
  const classes = useStyles();
  const theme = useTheme();
  const srcStyle = SOURCE_COLORS[c.source] || SOURCE_COLORS.specified;

  return (
    <Card variant="outlined" className={classes.card}>
      <Box display="flex" alignItems="flex-start" justifyContent="space-between">
        <Box display="flex" alignItems="center" style={{ gap: 8 }}>
          <ExtensionIcon style={{ fontSize: 18, color: theme.palette.text.secondary, opacity: 0.6 }} />
          <Typography className={classes.fqcn}>{c.fqcn}</Typography>
        </Box>
        {c.violations > 0 && (
          <span
            onClick={onNavigateToDependencies}
            style={{
              fontSize: 11,
              fontWeight: 600,
              padding: '1px 7px',
              borderRadius: 10,
              backgroundColor: `${SEVERITY_COLORS.high}15`,
              color: SEVERITY_COLORS.high,
              cursor: onNavigateToDependencies ? 'pointer' : 'default',
              flexShrink: 0,
            }}
          >
            {c.violations} violation{c.violations !== 1 ? 's' : ''}
          </span>
        )}
        {c.violations === 0 && (
          <CheckCircleOutlineIcon style={{ fontSize: 16, color: '#3e8635', opacity: 0.6, flexShrink: 0 }} />
        )}
      </Box>

      <Box className={classes.meta}>
        <Typography style={{ fontFamily: 'monospace', fontSize: 12, color: theme.palette.text.secondary }}>
          {c.version}
        </Typography>
        <Tooltip title={SOURCE_TOOLTIPS[c.source] ?? c.source} arrow>
          <span className={classes.sourceBadge} style={{ backgroundColor: srcStyle.bg, color: srcStyle.color }}>
            {c.source}
          </span>
        </Tooltip>
      </Box>

      <a
        href={galaxyUrl(c.fqcn)}
        target="_blank"
        rel="noopener noreferrer"
        className={classes.galaxyLink}
        onClick={(e) => e.stopPropagation()}
      >
        View on Galaxy <OpenInNewIcon style={{ fontSize: 12 }} />
      </a>
    </Card>
  );
}
