import React, { useEffect } from 'react';
import { Route, Routes, Navigate, Outlet, useLocation } from 'react-router-dom';
import { CircularProgress } from '@material-ui/core';
import { RequirePermission } from '@backstage/plugin-permission-react';
import { catalogEntityCreatePermission } from '@backstage/plugin-catalog-common/alpha';
import {
  useApi,
  discoveryApiRef,
  fetchApiRef,
} from '@backstage/core-plugin-api';
import {
  executionEnvironmentsViewPermission,
  collectionsViewPermission,
  gitRepositoriesViewPermission,
  templatesViewPermission,
  historyViewPermission,
} from '@ansible/backstage-rhaap-common/permissions';

import { HomeComponent } from '../Home';
import { CatalogImport } from '../CatalogImport';
import { useIsSuperuser } from '../../hooks';
import { CreateTask } from '../CreateTask';
import { RunTask } from '../RunTask';
import { FeedbackFooter } from '../feedback/FeedbackFooter';
import { TaskList } from '../TaskList';
import { CatalogItemsDetails } from '../CatalogItemDetails';
import { EETabs } from '../ExecutionEnvironments';
import { EEDetailsPage } from '../ExecutionEnvironments/catalog/EEDetailsPage';
import { CollectionsCatalogPage } from '../CollectionsCatalog';
import { CollectionDetailsPage } from '../CollectionsCatalog/CollectionDetailsPage';
import { GitRepositoriesPage } from '../GitRepositories';
import { RepositoryDetailsPage } from '../GitRepositories/RepositoryDetailsPage';
import { ApmeAdminPage } from '../Admin/ApmeAdminPage';
import { IntegrationsPage } from '../Admin/IntegrationsPage';
import { GeneralPage } from '../Admin/GeneralPage';
import {
  NotificationProvider,
  NotificationStack,
  useNotifications,
  syncPollingService,
} from '../notifications';

const RequireSuperuser = ({ children }: { children: React.ReactNode }) => {
  const { isSuperuser, loading, error } = useIsSuperuser();
  if (loading) {
    return (
      <div
        data-testid="superuser-loading"
        style={{ display: 'flex', justifyContent: 'center', padding: '2rem' }}
      >
        <CircularProgress />
      </div>
    );
  }
  if (error || !isSuperuser) {
    return <Navigate to="/self-service/repositories/catalog" replace />;
  }
  return <>{children}</>;
};

const RouteViewContent = () => {
  const { notifications, removeNotification } = useNotifications();
  const location = useLocation();
  const discoveryApi = useApi(discoveryApiRef);
  const fetchApi = useApi(fetchApiRef);

  // Initialize the global sync polling service
  useEffect(() => {
    syncPollingService.initialize(discoveryApi, fetchApi);
  }, [discoveryApi, fetchApi]);

  return (
    <>
      <Routes>
        <Route
          path="catalog"
          element={
            <RequirePermission permission={templatesViewPermission}>
              <HomeComponent key={location.key} />
            </RequirePermission>
          }
        />
        <Route
          path="catalog/:namespace/:templateName"
          element={
            <RequirePermission permission={templatesViewPermission}>
              <CatalogItemsDetails />
            </RequirePermission>
          }
        />
        <Route
          path="catalog-import"
          element={
            <RequirePermission permission={catalogEntityCreatePermission}>
              <RequireSuperuser>
                <CatalogImport />
              </RequireSuperuser>
            </RequirePermission>
          }
        />
        <Route path="create">
          <Route
            path="templates/:namespace/:templateName"
            element={
              <RequirePermission permission={templatesViewPermission}>
                <CreateTask />
              </RequirePermission>
            }
          />
          <Route
            path="tasks"
            element={
              <RequirePermission permission={historyViewPermission}>
                <TaskList />
              </RequirePermission>
            }
          />
          <Route
            path="tasks/:taskId"
            element={
              <RequirePermission permission={historyViewPermission}>
                <RunTask />
              </RequirePermission>
            }
          />
        </Route>
        <Route
          path="ee"
          element={
            <RequirePermission permission={executionEnvironmentsViewPermission}>
              <Outlet />
            </RequirePermission>
          }
        >
          <Route index element={<Navigate to="catalog" replace />} />
          <Route path="catalog" element={<EETabs />} />
          <Route path="create" element={<EETabs />} />
          <Route path="*" element={<Navigate to="catalog" replace />} />
        </Route>
        <Route
          path="catalog/:templateName"
          element={
            <RequirePermission permission={executionEnvironmentsViewPermission}>
              <EEDetailsPage />
            </RequirePermission>
          }
        />
        <Route
          path="collections"
          element={
            <RequirePermission permission={collectionsViewPermission}>
              <CollectionsCatalogPage />
            </RequirePermission>
          }
        />
        <Route
          path="collections/:collectionName"
          element={
            <RequirePermission permission={collectionsViewPermission}>
              <CollectionDetailsPage />
            </RequirePermission>
          }
        />
        <Route
          path="repositories"
          element={
            <RequirePermission permission={gitRepositoriesViewPermission}>
              <Outlet />
            </RequirePermission>
          }
        >
          <Route index element={<Navigate to="catalog" replace />} />
          <Route path="catalog" element={<GitRepositoriesPage />} />
          <Route path="quality" element={<GitRepositoriesPage />} />
          <Route path="ci-activity" element={<GitRepositoriesPage />} />
          <Route path="create" element={<GitRepositoriesPage />} />
          <Route path=":repositoryName" element={<RepositoryDetailsPage />} />
        </Route>
        <Route path="admin">
          <Route path="general" element={<GeneralPage />} />
          <Route path="integrations" element={<IntegrationsPage />} />
          <Route path="integrations/quality" element={<ApmeAdminPage />} />
        </Route>
        {/* Default redirects */}
        <Route
          path="/catalog/*"
          element={<Navigate to="/self-service/repositories/catalog" />}
        />
        <Route path="*" element={<Navigate to="/self-service/repositories/catalog" />} />
      </Routes>
      <FeedbackFooter />
      <NotificationStack
        notifications={notifications}
        onClose={removeNotification}
      />
    </>
  );
};

export const RouteView = () => {
  return (
    <NotificationProvider>
      <RouteViewContent />
    </NotificationProvider>
  );
};
