type ReadmeStateSetters = {
  setReadmeContent: (value: string) => void;
  setReadmeLoading: (value: boolean) => void;
  setScmIntegrationAuthError: (value: boolean) => void;
};

type BackendReadmePlan = {
  kind: 'backend';
  scmProvider: string;
  scmHost: string;
  scmOrg: string;
  scmRepo: string;
  filePath: string;
  gitRef: string;
};

type DirectReadmePlan = {
  kind: 'direct';
  defaultBranch: string;
  filePath: string;
};

function resolveReadmeLoadPlan(
  entity: Entity,
): BackendReadmePlan | DirectReadmePlan {
  const annotations = entity.metadata?.annotations || {};
  const spec = (entity.spec || {}) as { repository_default_branch?: string };
  const scmProvider = (annotations['ansible.io/scm-provider'] ?? '')
    .toString()
    .toLowerCase();
  const scmHost = annotations['ansible.io/scm-host'];
  const scmOrg = annotations['ansible.io/scm-organization'];
  const scmRepo = annotations['ansible.io/scm-repository'];
  const defaultBranch = spec.repository_default_branch || 'main';
  const filePath = 'README.md';

  const canUseBackend =
    ['github', 'gitlab'].includes(scmProvider) &&
    scmHost &&
    scmOrg &&
    scmRepo &&
    defaultBranch;

  if (canUseBackend) {
    return {
      kind: 'backend',
      scmProvider,
      scmHost: String(scmHost),
      scmOrg: String(scmOrg),
      scmRepo: String(scmRepo),
      filePath,
      gitRef: defaultBranch,
    };
  }
  return { kind: 'direct', defaultBranch, filePath };
}

function startBackendReadmeFetch(
  plan: BackendReadmePlan,
  discoveryApi: DiscoveryApi,
  fetchApi: FetchApi,
  isCancelled: () => boolean,
  setters: ReadmeStateSetters,
): void {
  const { setReadmeContent, setReadmeLoading, setScmIntegrationAuthError } =
    setters;

  fetchGitFileContentFromBackend(discoveryApi, fetchApi, {
    scmProvider: plan.scmProvider,
    scmHost: plan.scmHost,
    scmOrg: plan.scmOrg,
    scmRepo: plan.scmRepo,
    filePath: plan.filePath,
    gitRef: plan.gitRef,
  })
    .then(outcome => {
      if (isCancelled()) return;
      if (outcome.ok) {
        setReadmeContent(outcome.data);
        setScmIntegrationAuthError(false);
      } else if (outcome.reason === 'integration_auth') {
        setScmIntegrationAuthError(true);
      } else {
        setReadmeContent('');
        setScmIntegrationAuthError(false);
      }
    })
    .catch(() => {
      if (isCancelled()) return;
      setReadmeContent('');
      setScmIntegrationAuthError(false);
    })
    .finally(() => {
      if (!isCancelled()) setReadmeLoading(false);
    });
}

function startDirectReadmeFetch(
  entity: Entity,
  plan: DirectReadmePlan,
  isCancelled: () => boolean,
  setters: ReadmeStateSetters,
): void {
  const { setReadmeContent, setReadmeLoading, setScmIntegrationAuthError } =
    setters;

  setScmIntegrationAuthError(false);

  const sourceUrl = getSourceUrl(entity);
  if (sourceUrl) {
    const fetchUrl = buildRawReadmeFetchUrl(
      sourceUrl,
      plan.defaultBranch,
      plan.filePath,
    );
    if (fetchUrl) {
      fetch(fetchUrl)
        .then(response => (response.ok ? response.text() : ''))
        .then(text => {
          if (!isCancelled()) setReadmeContent(text);
        })
        .catch(() => {
          if (!isCancelled()) setReadmeContent('');
        })
        .finally(() => {
          if (!isCancelled()) setReadmeLoading(false);
        });
      return;
    }
    setReadmeContent('');
    setReadmeLoading(false);
    return;
  }
  setReadmeContent('');
  setReadmeLoading(false);
}

const RepositoryDetailsPageInner = () => {
  const classes = useCollectionsStyles();
  const theme = useTheme();
  const isDark = theme.palette.type === 'dark';
  const navigate = useNavigate();
  const { repositoryName } = useParams<{ repositoryName: string }>();
  const catalogApi = useApi(catalogApiRef);
  const discoveryApi = useApi<DiscoveryApi>(discoveryApiRef);
  const fetchApi = useApi<FetchApi>(fetchApiRef);
  const rootLink = useRouteRef(rootRouteRef);

  const [searchParams, setSearchParams] = useSearchParams();
  const [entity, setEntity] = useState<Entity | null>(null);
  const [loading, setLoading] = useState(true);
  const [readmeContent, setReadmeContent] = useState('');
  const [readmeLoading, setReadmeLoading] = useState(false);
  const [scmIntegrationAuthError, setScmIntegrationAuthError] = useState(false);
  // bannerModal removed — category breakdown on Overview tab replaces it
  const [qualityNavKey, setQualityNavKey] = useState(0);
  const [actionsAnchor, setActionsAnchor] = useState<null | HTMLElement>(null);

  const TAB_NAMES = ['overview', 'quality', 'dependencies', 'ci-activity', 'collections'] as const;
  const tabFromUrl = searchParams.get('tab');
  const initialTab = TAB_NAMES.indexOf(tabFromUrl as any);
  const [tab, setTab] = useState(initialTab >= 0 ? initialTab : 0);

  const handleTabChange = (_: unknown, v: number) => {
    setTab(v);
    const newParams = new URLSearchParams(searchParams);
    if (v === 0) { newParams.delete('tab'); }
    else { newParams.set('tab', TAB_NAMES[v]); }
    if (v !== 1) {
      newParams.delete('rule');
      newParams.delete('severity');
      newParams.delete('category');
    }
    setSearchParams(newParams, { replace: true });
  };

  const qualityData = useMemo(
    () => (repositoryName ? getProjectQuality(repositoryName) : null),
    [repositoryName],
  );
  const violationCount = repositoryName ? getProjectViolationCount(repositoryName) : undefined;
  const severityBreakdown = repositoryName ? getProjectSeverityBreakdown(repositoryName) : undefined;
  const collections = useMemo(
    () => (repositoryName ? getProjectCollections(repositoryName) : []),
    [repositoryName],
  );

  const fetchEntity = useCallback(() => {
    if (!repositoryName) return;

    setLoading(true);
    catalogApi
      .getEntities({
        filter: [
          {
            'metadata.name': repositoryName,
            kind: 'Component',
            'spec.type': 'git-repository',
          },
        ],
      })
      .then(response => {
        const items = Array.isArray(response) ? response : response.items || [];
        const first = items.length > 0 ? items[0] : null;
        setEntity(first);
      })
      .catch(() => {
        setEntity(null);
      })
      .finally(() => {
        setLoading(false);
      });
  }, [catalogApi, repositoryName]);

  useEffect(() => {
    fetchEntity();
  }, [fetchEntity]);

  useEffect(() => {
    setScmIntegrationAuthError(false);
  }, [repositoryName]);

  useEffect(() => {
    if (!entity) {
      return () => {};
    }

    // Wait until catalog row matches the URL; fetchEntity does not clear `entity` before the next response.
    if (repositoryName && entity.metadata?.name !== repositoryName) {
      return () => {};
    }

    let cancelled = false;
    const isCancelled = () => cancelled;

    const plan = resolveReadmeLoadPlan(entity);
    setReadmeLoading(true);

    const setters: ReadmeStateSetters = {
      setReadmeContent,
      setReadmeLoading,
      setScmIntegrationAuthError,
    };

    if (plan.kind === 'backend') {
      startBackendReadmeFetch(
        plan,
        discoveryApi,
        fetchApi,
        isCancelled,
        setters,
      );
    } else {
      startDirectReadmeFetch(entity, plan, isCancelled, setters);
    }

    return () => {
      cancelled = true;
      setReadmeLoading(false);
    };
  }, [entity, discoveryApi, fetchApi, repositoryName]);

  // Demo README fallback for prototype
  useEffect(() => {
    if (repositoryName === 'rhel-patching' && !readmeContent && !readmeLoading) {
      setReadmeContent(`# rhel-patching

Ansible automation for RHEL system patching — applies security updates, kernel patches, and compliance verification across managed hosts.

## Quick Start

\`\`\`bash
ansible-playbook -i inventory/production playbook-l057-wrong-module.yml --tags security
\`\`\`

## Playbooks

| Playbook | Purpose |
|---|---|
| \`playbook-l057-wrong-module.yml\` | Full patching run — security updates, package upgrades, service restarts |
| \`roles/broken_role/tasks/main.yml\` | Post-patch validation and compliance checks |

## Inventory

Hosts are organized by environment in \`inventory/\`. Group variables in \`group_vars/all/\` hold shared configuration including notification endpoints and patching windows.

## Templates

Configuration templates in \`templates/\` are rendered during patching to update service configs (e.g., \`app.conf.j2\`).

## Collections

This repository depends on two collections:

- **ansible.posix** — RHEL-specific modules (mount, firewalld, selinux)
- **community.general** — Utility modules (timezone, hostname, packaging)

## Contributing

1. Create a feature branch from \`main\`
2. Run \`ansible-lint\` before pushing
3. Open a PR — quality scans run automatically
`);
    }
  }, [repositoryName, readmeContent, readmeLoading]);

  const handleNavigateToCatalog = useCallback(() => {
    navigate(`${rootLink()}/repositories/catalog`);
  }, [navigate, rootLink]);

  const handleViewSource = useCallback(() => {
    if (!entity) return;
    const url = getSourceUrl(entity);
    if (url) {
      globalThis.open(url, '_blank');
    }
  }, [entity]);

  const hasSourceUrl = useCallback(() => {
    return entity ? Boolean(getSourceUrl(entity)) : false;
  }, [entity]);

  const displayName =
    (entity?.spec as { repository_name?: string })?.repository_name ??
    entity?.metadata?.title ??
    repositoryName ??
    'Repository';

  if (loading) {
    return (
      <Box className={classes.detailsContainer}>
        <Typography>Loading...</Typography>
      </Box>
    );
  }

  if (!entity) {
    return (
      <Box className={classes.detailsContainer}>
        <RepositoryBreadcrumbs
          repositoryName={repositoryName ?? 'Unknown'}
          onNavigateToCatalog={handleNavigateToCatalog}
        />
        <EmptyState />
      </Box>
    );
  }

  if (scmIntegrationAuthError) {
    return (
      <Box className={classes.detailsContainer}>
        <RepositoryBreadcrumbs
          repositoryName={displayName}
          onNavigateToCatalog={handleNavigateToCatalog}
        />
        <ScmIntegrationAuthError resourceLabel="repository" />
      </Box>
    );
  }

  return (
    <Box className={classes.detailsContainer}>
      <RepositoryBreadcrumbs
        repositoryName={displayName}
        onNavigateToCatalog={handleNavigateToCatalog}
      />

      <Box className={classes.detailsHeader}>
        <Box>
          <Typography className={classes.detailsTitleText}>
            {displayName}
          </Typography>
          {entity.metadata?.description && (
            <Typography className={classes.detailsDescription}>
              {entity.metadata.description}
            </Typography>
          )}
        </Box>
        <Button
          variant="contained"
          color="primary"
          endIcon={<ArrowDropDownIcon />}
          onClick={(e) => setActionsAnchor(e.currentTarget)}
          style={{ whiteSpace: 'nowrap', flexShrink: 0, marginLeft: 24, textTransform: 'none' }}
        >
          Actions
        </Button>
        <Menu
          anchorEl={actionsAnchor}
          open={!!actionsAnchor}
          onClose={() => setActionsAnchor(null)}
          getContentAnchorEl={null}
          anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
          transformOrigin={{ vertical: 'top', horizontal: 'right' }}
        >
          {hasSourceUrl() && (
            <MenuItem onClick={() => { setActionsAnchor(null); handleViewSource(); }} style={{ justifyContent: 'space-between', gap: 16 }}>
              <ListItemText primary="View in source" />
              <OpenInNewIcon fontSize="small" style={{ color: 'inherit', opacity: 0.6 }} />
            </MenuItem>
          )}
          <MenuItem onClick={() => { setActionsAnchor(null); }} style={{ justifyContent: 'space-between', gap: 16 }}>
            <ListItemText primary="Sync with source" />
            <SyncIcon fontSize="small" style={{ color: 'inherit', opacity: 0.6 }} />
          </MenuItem>
          <MenuItem onClick={() => { setActionsAnchor(null); }} style={{ justifyContent: 'space-between', gap: 16 }}>
            <ListItemText primary="Run quality scan" />
            <PlayArrowIcon fontSize="small" style={{ color: 'inherit', opacity: 0.6 }} />
          </MenuItem>
          <MenuItem onClick={() => { setActionsAnchor(null); }} style={{ justifyContent: 'space-between', gap: 16 }}>
            <ListItemText primary="Edit in Dev Spaces" />
            <OpenInNewIcon fontSize="small" style={{ color: 'inherit', opacity: 0.6 }} />
          </MenuItem>
        </Menu>
      </Box>

      {/* Compatibility banner removed — category breakdown on Overview tab replaces it */}

      <Tabs
        value={tab}
        onChange={handleTabChange}
        className={classes.detailsTabs}
      >
        <Tab label="Overview" />
        <Tab label={
          violationCount !== undefined && violationCount > 0 ? (
            <Box display="inline-flex" alignItems="center" style={{ gap: 6 }}>
              Quality
              <span style={{
                fontSize: 11,
                fontWeight: 600,
                padding: '1px 7px',
                borderRadius: 10,
                backgroundColor: `${SEVERITY_COLORS.critical}15`,
                color: SEVERITY_COLORS.critical,
              }}>
                {violationCount}
              </span>
            </Box>
          ) : 'Quality'
        } />
        <Tab label={(() => {
          const depCount = qualityData?.violations.filter(v => v.category === 'dependencies').length ?? 0;
          return depCount > 0 ? (
            <Box display="inline-flex" alignItems="center" style={{ gap: 6 }}>
              Dependencies
              <span style={{
                fontSize: 11,
                fontWeight: 600,
                padding: '1px 7px',
                borderRadius: 10,
                backgroundColor: `${SEVERITY_COLORS.high}15`,
                color: SEVERITY_COLORS.high,
              }}>
                {depCount}
              </span>
            </Box>
          ) : 'Dependencies';
        })()} />
        <Tab label="CI Activity" />
        <Tab label={
          collections.length > 0 ? (
            <Box display="inline-flex" alignItems="center" style={{ gap: 6 }}>
              Collections
              <span style={{
                fontSize: 11,
                fontWeight: 600,
                padding: '1px 7px',
                borderRadius: 10,
                backgroundColor: theme.palette.type === 'dark' ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)',
                color: theme.palette.text.secondary,
              }}>
                {collections.length}
              </span>
            </Box>
          ) : 'Collections'
        } />
      </Tabs>

      {tab === 0 && (
        <Box>
          <Box className={classes.detailsContent}>
            <Box className={classes.detailsLeftColumn}>
              {/* Quality summary card */}
              {qualityData && qualityData.totalViolations > 0 && (() => {
                const CATEGORY_META: { key: ViolationCategory; label: string; tip: string }[] = [
                  { key: 'modernize', label: 'Compatibility', tip: 'Deprecated syntax, removed modules, and version-specific issues that block AAP upgrades' },
                  { key: 'secrets', label: 'Secrets', tip: 'Hardcoded credentials, tokens, and keys that should use vault or an external secrets manager' },
                  { key: 'risk', label: 'Risk', tip: 'Security risks such as missing file permissions, unsafe shell usage, and privilege escalation' },
                  { key: 'lint', label: 'Lint', tip: 'Code quality issues — naming conventions, FQCN usage, Jinja spacing, and changed_when' },
                  { key: 'policy', label: 'Policy', tip: 'Organizational policy violations defined by OPA rules' },
                  { key: 'dependencies', label: 'Dependencies', tip: 'Outdated or vulnerable collection and Python dependencies' },
                ];
                return (
                  <Card variant="outlined" style={{ borderRadius: 8, marginBottom: 16 }}>
                    <CardContent style={{ padding: '14px 16px 12px' }}>
                      <Box display="flex" alignItems="center" justifyContent="space-between" style={{ marginBottom: 8 }}>
                        <Typography style={{ fontSize: 12, fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.5, color: theme.palette.text.secondary }}>
                          Quality
                        </Typography>
                        <Typography
                          component="span"
                          style={{ fontSize: 12, color: theme.palette.primary.main, cursor: 'pointer' }}
                          onClick={() => handleTabChange(null, 1)}
                        >
                          View details →
                        </Typography>
                      </Box>

                      <Box display="flex" alignItems="baseline" style={{ gap: 6, marginBottom: 4 }}>
                        <Typography style={{ fontSize: 20, fontWeight: 600, color: SEVERITY_COLORS.critical, lineHeight: 1 }}>
                          {qualityData.totalViolations}
                        </Typography>
                        <Typography style={{ fontSize: 12, color: theme.palette.text.secondary }}>
                          violation{qualityData.totalViolations !== 1 ? 's' : ''} · {qualityData.violations.filter(v => v.fixTier !== 'manual').length} fixable
                        </Typography>
                      </Box>

                      <Box display="flex" style={{ height: 6, borderRadius: 3, overflow: 'hidden', marginBottom: 8 }}>
                        {(['critical', 'high', 'medium', 'low', 'info'] as SeverityClass[]).map(sev => {
                          const count = qualityData.severityBreakdown[sev] ?? 0;
                          if (!count) return null;
                          return <Box key={sev} style={{ flex: count, backgroundColor: SEVERITY_COLORS[sev] }} />;
                        })}
                      </Box>

                      <Box display="flex" flexWrap="wrap" style={{ gap: '2px 10px', marginBottom: 10 }}>
                        {(['critical', 'high', 'medium', 'low', 'info'] as SeverityClass[]).map(sev => {
                          const count = qualityData.severityBreakdown[sev] ?? 0;
                          if (!count) return null;
                          return (
                            <Typography key={sev} style={{ fontSize: 11, color: theme.palette.text.secondary }}>
                              <strong style={{ color: SEVERITY_COLORS[sev] }}>{count}</strong>{' '}
                              <span style={{ textTransform: 'capitalize' }}>{sev}</span>
                            </Typography>
                          );
                        })}
                      </Box>

                      {(() => {
                        const total = qualityData.totalViolations || 1;
                        const isDark = theme.palette.type === 'dark';
                        const trackColor = isDark ? 'rgba(255,255,255,0.08)' : '#e8e8e8';
                        return CATEGORY_META.map(({ key, label, tip }) => {
                          const catViolations = qualityData.violations.filter(v => v.category === key);
                          const count = catViolations.length;
                          if (!count) return null;
                          const catBySev: Partial<Record<SeverityClass, number>> = {};
                          catViolations.forEach(v => { catBySev[v.severity] = (catBySev[v.severity] ?? 0) + 1; });
                          const pct = (count / total) * 100;
                          return (
                            <Box
                              key={key}
                              display="flex"
                              alignItems="center"
                              style={{ cursor: 'pointer', padding: '5px 0', gap: 10 }}
                              onClick={() => {
                                const newParams = new URLSearchParams(searchParams);
                                newParams.set('tab', 'quality');
                                newParams.set('category', key);
                                setSearchParams(newParams, { replace: true });
                                setTab(1);
                                setQualityNavKey(k => k + 1);
                              }}
                            >
                              <Typography component="span" style={{ fontSize: 12, color: theme.palette.primary.main, flexShrink: 0, whiteSpace: 'nowrap', display: 'inline-flex', alignItems: 'center', gap: 3, width: 130 }}>
                                {label}
                                <Tooltip title={tip} arrow enterDelay={200}>
                                  <HelpOutlineIcon style={{ fontSize: 13, color: theme.palette.text.disabled, cursor: 'help' }} />
                                </Tooltip>
                                <span style={{
                                  fontSize: 11,
                                  fontWeight: 600,
                                  padding: '1px 7px',
                                  borderRadius: 10,
                                  backgroundColor: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)',
                                  color: theme.palette.text.secondary,
                                  marginLeft: 2,
                                }}>{count}</span>
                              </Typography>
                              <Box style={{ flex: 1, minWidth: 0, height: 6, borderRadius: 3, backgroundColor: trackColor, overflow: 'hidden' }}>
                                <Box display="flex" style={{ height: '100%', width: `${pct}%`, borderRadius: 3 }}>
                                  {(['critical', 'high', 'medium', 'low', 'info'] as SeverityClass[]).map(sev => {
                                    const n = catBySev[sev] ?? 0;
                                    if (!n) return null;
                                    return <Box key={sev} style={{ flex: n, backgroundColor: SEVERITY_COLORS[sev] }} />;
                                  })}
                                </Box>
                              </Box>
                            </Box>
                          );
                        });
                      })()}
                    </CardContent>
                  </Card>
                );
              })()}

              <RepositoryReadmeCard
                readmeContent={readmeContent}
                isLoading={readmeLoading}
              />
            </Box>
            <Box className={classes.detailsRightColumn}>
              <RepositoryAboutCard
                entity={entity}
                onViewSource={handleViewSource}
                onNavigateToCollections={() => handleTabChange(null, 4)}
              />
            </Box>
          </Box>
        </Box>
      )}

      {tab === 1 && (
        <Box style={{ width: '100%', flex: 1 }}>
          <QualityTab
            key={qualityNavKey}
            quality={qualityData}
            projectName={repositoryName ?? ''}
            initialSeverity={searchParams.get('severity') as SeverityClass | null}
            initialRuleFilter={searchParams.get('rule')}
            initialCategoryFilter={searchParams.get('category') as any}
            repoUrl={entity ? getSourceUrl(entity) ?? undefined : undefined}
            branch={(entity?.spec as any)?.repository_default_branch ?? 'main'}
          />
        </Box>
      )}

      {tab === 2 && (
        <Box style={{ width: '100%', flex: 1 }}>
          <DependenciesTab
            quality={qualityData}
            projectName={repositoryName ?? ''}
            repoUrl={entity ? getSourceUrl(entity) ?? undefined : undefined}
            branch={(entity?.spec as any)?.repository_default_branch ?? 'main'}
            onNavigateToQuality={(category) => {
              const newParams = new URLSearchParams(searchParams);
              newParams.set('tab', 'quality');
              if (category) newParams.set('category', category);
              else newParams.delete('category');
              setSearchParams(newParams, { replace: true });
              setTab(1);
              setQualityNavKey(k => k + 1);
            }}
          />
        </Box>
      )}

      {tab === 3 && (
        <Box
          className={classes.detailsContent}
          style={{ width: '100%', flex: 1 }}
        >
          <RepositoriesCIActivityTab filterByEntity={entity} />
        </Box>
      )}

      {tab === 4 && (
        <Box style={{ width: '100%', flex: 1 }}>
          <RepositoryCollectionsTab
            quality={qualityData}
            projectName={repositoryName ?? ''}
            onNavigateToDependencies={() => {
              const newParams = new URLSearchParams(searchParams);
              newParams.set('tab', 'dependencies');
              setSearchParams(newParams, { replace: true });
              setTab(2);
            }}
          />
        </Box>
      )}

      {/* Compatibility modal removed — category breakdown on Overview tab replaces it */}

    </Box>
  );
};

export const RepositoryDetailsPage = () => {
  return (
    <RequirePermission permission={gitRepositoriesViewPermission}>
      <RepositoryDetailsPageInner />
    </RequirePermission>
  );
};
