// ---------------------------------------------------------------------------
// Provider card component
// ---------------------------------------------------------------------------

function ProviderCardItem({ provider }: { provider: ProviderCard }) {
  const classes = useStyles();
  const navigate = useNavigate();

  const isConnected = provider.status === 'connected';

  return (
    <Card className={classes.card} elevation={0} variant="outlined">
      <CardContent className={classes.cardContent}>
        {/* Header: icon + title + chip */}
        <Box className={classes.cardHeader}>
          <Box
            className={classes.iconCircle}
            style={{ backgroundColor: provider.iconBg }}
          >
            {provider.icon}
          </Box>
          <Box flex={1} minWidth={0}>
            <Box className={classes.cardTitleRow}>
              <Typography
                className={classes.cardName}
                onClick={() => navigate(provider.configPath)}
              >
                {provider.name}
              </Typography>
              <Chip
                label={isConnected ? 'Connected' : 'Not connected'}
                size="small"
                className={
                  isConnected
                    ? classes.connectedChip
                    : classes.notConnectedChip
                }
              />
            </Box>
            <Typography className={classes.cardType}>
              {provider.type}
            </Typography>
          </Box>
        </Box>

        {/* Body: host or description */}
        {provider.host && (
          <Typography className={classes.cardHost}>{provider.host}</Typography>
        )}
        {provider.description && (
          <Typography className={classes.cardBody}>
            {provider.description}
          </Typography>
        )}
        {provider.lastSync && (
          <Typography className={classes.cardMeta}>
            {provider.lastSync}
          </Typography>
        )}
        {provider.stats && (
          <Typography className={classes.cardMeta}>
            {provider.stats}
          </Typography>
        )}

        {/* Footer actions */}
        <Box className={classes.cardFooter}>
          {isConnected && provider.lastSync && (
            <Tooltip title="Trigger a sync now">
              <button type="button" className={classes.actionLink}>
                <SyncIcon style={{ fontSize: 14 }} />
                Sync now
              </button>
            </Tooltip>
          )}
          <button
            type="button"
            className={classes.actionLink}
            onClick={() => navigate(provider.configPath)}
          >
            {isConnected ? 'Configure' : 'Connect'}
            <ArrowForwardIcon style={{ fontSize: 14 }} />
          </button>
        </Box>
      </CardContent>
    </Card>
  );
}

