function getSeverityStyle(severity: Severity): { bg: string; color: string } {
  return SEVERITY_STYLES[severity] ?? SEVERITY_STYLES.info;
}

function capitalize(str: string): string {
  return str.charAt(0).toUpperCase() + str.slice(1);
}


