function RulesSection({ targetVersion }: { targetVersion: string }) {
  const classes = useStyles();
  const theme = useTheme();

  const [rules, setRules] = useState<ApmeRule[]>(RULES);
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('');
  const [sourceFilter, setSourceFilter] = useState<string>('');

  const overrideCount = rules.filter(r => r.hasOverride).length;

  const toggleEnabled = (id: string) => {
    setRules(prev =>
      prev.map(r => (r.id === id ? { ...r, enabled: !r.enabled } : r)),
    );
  };

  const toggleEnforced = (id: string) => {
    setRules(prev =>
      prev.map(r => (r.id === id ? { ...r, enforced: !r.enforced } : r)),
    );
  };

  const handleEffectiveSeverityChange = (id: string, sev: Severity) => {
    setRules(prev =>
      prev.map(r => {
        if (r.id !== id) return r;
        return {
          ...r,
          effectiveSeverity: sev,
          hasOverride: sev !== r.defaultSeverity,
        };
      }),
    );
  };

  const filteredRules = useMemo(() => {
    return rules.filter(r => {
      if (categoryFilter && r.category !== categoryFilter) return false;
      if (sourceFilter && r.source !== sourceFilter) return false;
      if (search) {
        const q = search.toLowerCase();
        if (!r.id.toLowerCase().includes(q) && !r.description.toLowerCase().includes(q)) return false;
      }
      return true;
    });
  }, [rules, categoryFilter, sourceFilter, search]);

  return (
    <Box>
      <Typography variant="h5" className={classes.sectionTitle}>
        Rules
      </Typography>
      <Typography variant="caption" color="textSecondary" style={{ marginTop: 2 }}>
        Scanning against {TARGET_VERSIONS.find(v => v.value === targetVersion)?.label ?? targetVersion}
      </Typography>

      {/* Filter toolbar */}
      <Box className={classes.filterToolbar}>
        <TextField
          className={classes.searchField}
          variant="outlined"
          placeholder="Search by rule ID or description..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          InputProps={{
            startAdornment: (
              <InputAdornment position="start">
                <SearchIcon style={{ fontSize: 18, color: theme.palette.text.secondary }} />
              </InputAdornment>
            ),
          }}
        />
        <Select
          value={categoryFilter}
          onChange={e => setCategoryFilter(e.target.value as string)}
          variant="outlined"
          displayEmpty
          className={classes.filterSelect}
        >
          <MenuItem value="">All categories</MenuItem>
          {ALL_CATEGORIES.map(cat => (
            <MenuItem key={cat} value={cat}>{cat}</MenuItem>
          ))}
        </Select>
        <Select
          value={sourceFilter}
          onChange={e => setSourceFilter(e.target.value as string)}
          variant="outlined"
          displayEmpty
          className={classes.filterSelect}
        >
          <MenuItem value="">All sources</MenuItem>
          {ALL_SOURCES.map(src => (
            <MenuItem key={src} value={src}>{src}</MenuItem>
          ))}
        </Select>
      </Box>

      {/* Count */}
      <Typography variant="body2" color="textSecondary" style={{ marginBottom: 8 }}>
        {rules.length} registered · {overrideCount} with overrides
      </Typography>

      {/* Table */}
      <Card className={classes.rulesCard} elevation={0}>
        <Box className={classes.tableHeader}>
          <Tooltip title="Unique identifier for this scanning rule (e.g. L003, M001, SEC001)" arrow placement="top">
            <Box className={classes.tableHeaderCell}>Rule ID <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
          <Box className={classes.tableHeaderCell}>Description</Box>
          <Tooltip title="The validator backend that executes this rule: native (Python), opa (Rego policy), ansible (runtime checks), or gitleaks (secrets detection)" arrow placement="top">
            <Box className={classes.tableHeaderCell}>Source <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
          <Tooltip title="Rule category: aap (AAP compatibility), lint (code quality), modernize (version migration), risk (security risk), or secrets (credential detection)" arrow placement="top">
            <Box className={classes.tableHeaderCell}>Category <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
          <Tooltip title="The severity assigned by the rule author. Cannot be changed." arrow placement="top">
            <Box className={classes.tableHeaderCell}>Default <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
          <Tooltip title="The severity applied during scanning. Override the default to raise or lower priority for your organization." arrow placement="top">
            <Box className={classes.tableHeaderCell}>Effective <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
          <Tooltip title="Whether this rule is active during scans. Disabled rules are skipped." arrow placement="top">
            <Box className={classes.tableHeaderCell}>Status <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
          <Tooltip title="Enforced rules cause scans to fail when violations are found. Non-enforced rules report warnings only." arrow placement="top">
            <Box className={classes.tableHeaderCell}>Enforced <HelpOutlineIcon className={classes.helpIcon} /></Box>
          </Tooltip>
        </Box>

        {filteredRules.length === 0 ? (
          <Box className={classes.emptyState}>
            <Typography variant="body2">No rules match the current filters.</Typography>
          </Box>
        ) : (
          filteredRules.map(rule => (
            <Box
              key={rule.id}
              className={`${classes.tableRow} ${!rule.enabled ? classes.tableRowDisabled : ''}`}
            >
              <Typography className={classes.ruleId}>{rule.id}</Typography>
              <Typography className={classes.ruleDescription} noWrap>{rule.description}</Typography>
              <Typography variant="body2" style={{ fontSize: '0.8125rem' }}>{rule.source}</Typography>
              <Typography variant="body2" style={{ fontSize: '0.8125rem' }}>{rule.category}</Typography>
              <Box>
                <span
                  className={classes.severityChip}
                  style={{ backgroundColor: getSeverityStyle(rule.defaultSeverity).bg, color: getSeverityStyle(rule.defaultSeverity).color }}
                >
                  {rule.defaultSeverity}
                </span>
              </Box>
              <Box>
                <Select
                  value={rule.effectiveSeverity}
                  onChange={e => handleEffectiveSeverityChange(rule.id, e.target.value as Severity)}
                  variant="outlined"
                  className={classes.severitySelect}
                >
                  {SEVERITY_ORDER.map(sev => (
                    <MenuItem key={sev} value={sev} style={{ fontSize: '0.8125rem' }}>
                      {capitalize(sev)}
                    </MenuItem>
                  ))}
                </Select>
              </Box>
              <Box>
                <Switch
                  checked={rule.enabled}
                  onChange={() => toggleEnabled(rule.id)}
                  color="primary"
                  size="small"
                />
              </Box>
              <Box>
                <Switch
                  checked={rule.enforced}
                  onChange={() => toggleEnforced(rule.id)}
                  size="small"
                />
              </Box>
            </Box>
          ))
        )}
      </Card>
    </Box>
  );
}

